import React from 'react';
import { Link } from 'react-router-dom';

function Services() {
  // आपका दिया हुआ सटीक 9 सर्विसेस का डेटा
  const serviceData = [
    { id: 1, title: "Web Development", icon: "fas fa-code", desc: "Building high-speed, futuristic websites that convert visitors into loyal customers.", color: "#0d6efd", img: "https://images.unsplash.com" },
    { id: 2, title: "UI/UX Design", icon: "fas fa-layer-group", desc: "Pixel-perfect designs focused on user psychology and modern digital aesthetics.", color: "#dc3545", img: "https://images.unsplash.com" },
    { id: 3, title: "App Development", icon: "fas fa-mobile-alt", desc: "Powerful native and cross-platform apps with seamless and smooth user experiences.", color: "#198754", img: "https://images.unsplash.com" },
    { id: 4, title: "Assignment Support", icon: "fas fa-book-reader", desc: "Expert academic guidance to help you excel in your technical projects and finals.", color: "#ffc107", img: "https://images.unsplash.com" },
    { id: 5, title: "PPT Design", icon: "fas fa-file-powerpoint", desc: "High-impact visual storytelling that makes your presentations truly unforgettable.", color: "#0dcaf0", img: "https://images.unsplash.com" },
    { id: 6, title: "Report Writing", icon: "fas fa-file-signature", desc: "Professional, data-driven technical reports and structured business documentation.", color: "#6c757d", img: "https://images.unsplash.com" },
    { id: 7, title: "Digital Marketing", icon: "fas fa-bullhorn", desc: "Strategic growth campaigns to enhance your online presence and market reach.", color: "#343a40", img: "https://images.unsplash.com" },
    { id: 8, title: "Content Writing", icon: "fas fa-pen-nib", desc: "Engaging and SEO-optimized content that speaks your brand's unique voice.", color: "#0d6efd", img: "https://images.unsplash.com" },
    { id: 9, title: "SEO Optimization", icon: "fas fa-search-plus", desc: "Improve your search engine rankings and attract organic traffic with ease.", color: "#20c997", img: "https://images.unsplash.com" }
  ];

  return (
    <div className="services-container py-5" style={{ backgroundColor: '#f9fbff' }}>
      <div className="container py-4">
        {/* Header */}
        <div className="text-center mb-5">
          <h2 className="fw-bold display-5" style={{ color: '#1a1a1a' }}>My <span style={{ color: '#0d6efd' }}>Expertise</span></h2>
          <p className="text-muted fs-5">Innovative solutions for your digital and academic success.</p>
          <div className="mx-auto" style={{ width: '60px', height: '4px', background: '#0d6efd', borderRadius: '10px' }}></div>
        </div>

        {/* 9 Cards Grid */}
        <div className="row g-4">
          {serviceData.map((service) => (
            <div className="col-lg-4 col-md-6" key={service.id}>
              <div className="service-card shadow-sm">
                <div className="card-img-box">
                  <img src={service.img} alt={service.title} className="card-image" />
                  <div className="color-overlay" style={{ backgroundColor: `${service.color}dd` }}>
                    <i className={`${service.icon} fa-3x text-white mb-2`}></i>
                    <h5 className="text-white fw-bold">{service.title}</h5>
                  </div>
                </div>
                <div className="card-body p-4 bg-white">
                  <h5 className="fw-bold mb-2 text-dark">{service.title}</h5>
                  <p className="text-muted small mb-4" style={{ height: '50px' }}>{service.desc}</p>
                  <Link 
                    to="/register" 
                    className="btn w-100 rounded-pill fw-bold action-btn" 
                    style={{ border: `2px solid ${service.color}`, color: service.color }}
                  >
                    Get Started
                  </Link>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      <style>{`
        .service-card {
          border-radius: 20px;
          overflow: hidden;
          transition: all 0.4s ease;
          border: 1px solid #eee;
        }

        .card-img-box {
          position: relative;
          height: 180px;
          overflow: hidden;
        }

        .card-image {
          width: 100%;
          height: 100%;
          object-fit: cover;
          transition: 0.5s ease;
        }

        .color-overlay {
          position: absolute;
          top: 0; left: 0; width: 100%; height: 100%;
          display: flex; flex-direction: column;
          align-items: center; justify-content: center;
          opacity: 0;
          transition: 0.4s ease;
          transform: translateY(100%);
        }

        .service-card:hover {
          transform: translateY(-12px);
          box-shadow: 0 20px 40px rgba(0,0,0,0.1) !important;
        }

        .service-card:hover .color-overlay {
          opacity: 1;
          transform: translateY(0);
        }

        .service-card:hover .card-image {
          transform: scale(1.1);
        }

        .action-btn:hover {
          background-color: currentColor !important;
          color: white !important;
        }
      `}</style>
    </div>
  );
}

export default Services;
